import React from "react";
import { ArrowLeft, Download } from "lucide-react";
import { formatCurrency } from "../helpers/helpers";
import { jsPDF } from "jspdf";

export default function TransactionReceiptScreen({ transaction, onBack }) {
  if (!transaction) return null;

  const isDeposit = transaction.type.includes("deposit");

  // =======================
  // PDF DOWNLOAD FUNCTION
  // =======================
  const downloadReceipt = () => {
    const doc = new jsPDF();
    doc.setFontSize(18);
    doc.text("Nest Transaction Receipt", 20, 20);

    doc.setFontSize(12);
    doc.text(`Type: ${transaction.title}`, 20, 40);
    doc.text(
      `Amount: ${isDeposit ? "+" : "-"}₦${formatCurrency(
        transaction.amount
      )}`,
      20,
      50
    );
    doc.text(`Date: ${transaction.date}`, 20, 60);
    doc.text(
      `Reference: ${transaction.reference || transaction.id}`,
      20,
      70
    );

    doc.save(`Nest-Receipt-${transaction.id}.pdf`);
  };

  return (
    <div className="min-h-screen bg-[#f4f6fb] px-5 pt-6 pb-24 relative">
      {/* Header */}
      <div className="flex items-center gap-3 mb-8">
        <button onClick={onBack}>
          <ArrowLeft className="w-6 h-6 text-gray-700" />
        </button>
        <h1 className="text-xl font-semibold text-gray-900">
          Transaction Receipt
        </h1>

        {/* Download button */}
        <button
          onClick={downloadReceipt}
          className="ml-auto flex items-center gap-1 text-sm text-emerald-600 font-semibold"
        >
          <Download className="w-4 h-4" /> Download
        </button>
      </div>

      {/* Receipt Card */}
      <div className="bg-white rounded-2xl p-6 shadow-sm space-y-4">
        <div className="flex justify-between">
          <span className="text-gray-500">Type</span>
          <span className="font-semibold">{transaction.title}</span>
        </div>

        <div className="flex justify-between">
          <span className="text-gray-500">Amount</span>
          <span
            className={`font-bold ${
              isDeposit ? "text-emerald-600" : "text-gray-900"
            }`}
          >
            {isDeposit ? "+" : "-"}₦{formatCurrency(transaction.amount)}
          </span>
        </div>

        <div className="flex justify-between">
          <span className="text-gray-500">Date</span>
          <span className="font-medium">{transaction.date}</span>
        </div>

        <div className="pt-4 border-t">
          <p className="text-center text-sm text-emerald-600 font-medium">
            Transaction Successful
          </p>
        </div>
      </div>
    </div>
  );
}
